import re, sys
text = open('standard/GIP.md', encoding='utf-8').read()
m = re.search(r'existing repositor', text, re.IGNORECASE)
if not m:
    print('existing-repository marker not found for section-scoped check')
    sys.exit(1)
section = text[m.start():]
nxt = re.search(r'\n## ', section[1:])
if nxt:
    section = section[:nxt.start() + 1]
missing = []
for token in ('docs-standard-only', 'templates', 'full loop'):
    if token.lower() not in section.lower():
        missing.append(token)
if 'CONTEXT.md' not in section:
    missing.append('CONTEXT.md')
if 'AGENTS.md' not in section:
    missing.append('AGENTS.md')
if not (re.search(r'\bCI\b', section) or 'continuous integration' in section.lower()):
    missing.append('CI (standalone word) or continuous integration')
if missing:
    print('existing-repo section missing: ' + ', '.join(missing))
    sys.exit(1)
print('PASS')
